{
  "domain_analysis": {
    "business_context": "A logistics platform managing the lifecycle of parcel deliveries, from shipment creation through transit to final delivery, with weight-based pricing tiers.",
    "bounded_context": "Shipment Management — covers shipment lifecycle (creation, transit, delivery), address validation, weight constraints, and pricing classification.",
    "ubiquitous_language": [
      { "term": "Shipment", "definition": "A domain entity representing a parcel moving from a pickup address to a delivery address, progressing through defined lifecycle states." },
      { "term": "Pickup Address", "definition": "The origin location where the parcel is collected from the sender." },
      { "term": "Delivery Address", "definition": "The destination location where the parcel is delivered to the recipient." },
      { "term": "Shipment State", "definition": "The lifecycle phase of a shipment. Valid states: Pending, In Transit, Delivered. Transitions are strictly forward-only." },
      { "term": "Weight", "definition": "The physical mass of the parcel in kilograms, constrained to be positive and at most 1000 kg." },
      { "term": "Weight Bracket", "definition": "A pricing classification derived from shipment weight: Standard (0–10 kg], Heavy (10–50 kg], Freight (over 50 kg)." },
      { "term": "Standard", "definition": "Weight bracket for parcels weighing more than 0 kg up to and including 10 kg." },
      { "term": "Heavy", "definition": "Weight bracket for parcels weighing more than 10 kg up to and including 50 kg." },
      { "term": "Freight", "definition": "Weight bracket for parcels weighing more than 50 kg up to and including 1000 kg." }
    ]
  },

  "business_rules": [
    {
      "id": "BR-1",
      "rule": "A shipment can only be created when both a pickup address and a delivery address are provided.",
      "invariant": true,
      "invariant_justification": "A shipment without both endpoints is physically meaningless — it cannot be routed, priced, or fulfilled. Data integrity requires both addresses at creation time.",
      "testable_assertion": "Any attempt to create a shipment with a null or missing pickup address or delivery address must be rejected."
    },
    {
      "id": "BR-2",
      "rule": "Shipment state transitions are strictly forward-only: Pending → In Transit → Delivered. No backward transitions are permitted.",
      "invariant": true,
      "invariant_justification": "Backward transitions would corrupt audit trails, trigger incorrect billing reversals, and misrepresent the physical reality of parcel movement. State integrity depends on forward-only progression.",
      "testable_assertion": "A shipment in state 'In Transit' cannot transition to 'Pending'. A shipment in state 'Delivered' cannot transition to any other state."
    },
    {
      "id": "BR-3",
      "rule": "Delivered is a terminal state — no further state changes are allowed on a delivered shipment.",
      "invariant": true,
      "invariant_justification": "Delivery is a real-world finality event. Reopening a delivered shipment would break invoicing, proof-of-delivery records, and customer notifications. The system would be corrupt if this were violated.",
      "testable_assertion": "Any attempt to change the state of a shipment with state 'Delivered' must be rejected, regardless of the target state."
    },
    {
      "id": "BR-4",
      "rule": "Shipment weight must be strictly greater than 0 kg and must not exceed 1000 kg.",
      "invariant": true,
      "invariant_justification": "Zero or negative weight is physically impossible for a real parcel. The 1000 kg upper bound is a physical/operational constraint — exceeding it likely violates vehicle load limits and safety regulations.",
      "testable_assertion": "Shipment creation or weight update must reject weight <= 0 or weight > 1000."
    },
    {
      "id": "BR-5",
      "rule": "Weight bracket is determined by weight: Standard for weight in (0, 10], Heavy for weight in (10, 50], Freight for weight in (50, 1000].",
      "invariant": false,
      "invariant_justification": "The bracket thresholds (10 kg, 50 kg) and their labels are business pricing policy. A VP could adjust these thresholds without corrupting system state.",
      "testable_assertion": "A 10 kg shipment is classified as Standard. A 10.01 kg shipment is classified as Heavy. A 50 kg shipment is classified as Heavy. A 50.01 kg shipment is classified as Freight."
    },
    {
      "id": "BR-6",
      "rule": "A newly created shipment begins in the Pending state.",
      "invariant": true,
      "invariant_justification": "Creating a shipment directly in 'In Transit' or 'Delivered' would bypass operational steps (carrier assignment, pickup) and corrupt the lifecycle model.",
      "testable_assertion": "After successful creation, a shipment's state must be 'Pending'."
    }
  ],

  "acceptance_criteria": [
    {
      "id": "AC-1",
      "given": "A valid pickup address and a valid delivery address are provided",
      "when": "A shipment is created",
      "then": "The shipment is persisted in state 'Pending' with the given addresses and weight, and a weight bracket is assigned"
    },
    {
      "id": "AC-2",
      "given": "A pickup address is provided but no delivery address",
      "when": "A shipment creation is attempted",
      "then": "The creation is rejected with a validation error indicating the delivery address is required"
    },
    {
      "id": "AC-3",
      "given": "A delivery address is provided but no pickup address",
      "when": "A shipment creation is attempted",
      "then": "The creation is rejected with a validation error indicating the pickup address is required"
    },
    {
      "id": "AC-4",
      "given": "A shipment exists in state 'Pending'",
      "when": "The shipment is transitioned to 'In Transit'",
      "then": "The shipment state becomes 'In Transit'"
    },
    {
      "id": "AC-5",
      "given": "A shipment exists in state 'In Transit'",
      "when": "An attempt is made to transition it back to 'Pending'",
      "then": "The transition is rejected and the shipment remains 'In Transit'"
    },
    {
      "id": "AC-6",
      "given": "A shipment exists in state 'In Transit'",
      "when": "The shipment is transitioned to 'Delivered'",
      "then": "The shipment state becomes 'Delivered' and is finalized"
    },
    {
      "id": "AC-7",
      "given": "A shipment exists in state 'Delivered'",
      "when": "Any state change is attempted (to Pending, In Transit, or any other state)",
      "then": "The transition is rejected and the shipment remains 'Delivered'"
    },
    {
      "id": "AC-8",
      "given": "A shipment is being created with weight 0 kg, -5 kg, or 1001 kg",
      "when": "The creation is attempted",
      "then": "The creation is rejected with a validation error indicating weight must be between 0 (exclusive) and 1000 (inclusive)"
    },
    {
      "id": "AC-9",
      "given": "A shipment is created with weight 7 kg",
      "when": "The weight bracket is calculated",
      "then": "The shipment is classified as 'Standard'"
    },
    {
      "id": "AC-10",
      "given": "A shipment is created with weight 25 kg",
      "when": "The weight bracket is calculated",
      "then": "The shipment is classified as 'Heavy'"
    },
    {
      "id": "AC-11",
      "given": "A shipment is created with weight 75 kg",
      "when": "The weight bracket is calculated",
      "then": "The shipment is classified as 'Freight'"
    },
    {
      "id": "AC-12",
      "given": "A shipment is created with weight exactly 10 kg",
      "when": "The weight bracket is calculated",
      "then": "The shipment is classified as 'Standard'"
    },
    {
      "id": "AC-13",
      "given": "A shipment is created with weight exactly 50 kg",
      "when": "The weight bracket is calculated",
      "then": "The shipment is classified as 'Heavy'"
    }
  ],

  "edge_cases": [
    { "scenario": "Weight is exactly 10 kg (upper boundary of Standard)", "expected_behavior": "Classified as Standard. This is a boundary value — must be tested explicitly to confirm inclusive upper bound." },
    { "scenario": "Weight is 10.001 kg (just above Standard threshold)", "expected_behavior": "Classified as Heavy. Verifies the bracket boundary is exclusive on the lower side of Heavy." },
    { "scenario": "Weight is exactly 50 kg (upper boundary of Heavy)", "expected_behavior": "Classified as Heavy. Boundary value test for the Heavy/Freight cutoff." },
    { "scenario": "Weight is 50.001 kg (just above Heavy threshold)", "expected_behavior": "Classified as Freight." },
    { "scenario": "Weight is exactly 1000 kg (maximum allowed)", "expected_behavior": "Shipment is created and classified as Freight. The upper bound is inclusive." },
    { "scenario": "Weight is 1000.01 kg (just above maximum)", "expected_behavior": "Shipment creation is rejected — exceeds the 1000 kg limit." },
    { "scenario": "Weight is 0.001 kg (smallest positive weight)", "expected_behavior": "Shipment is created and classified as Standard. Verifies the lower bound is exclusive of zero." },
    { "scenario": "Attempting Pending → Delivered directly (skipping In Transit)", "expected_behavior": "Spec does not explicitly address this. See escalation. Recommended: reject as invalid skip." },
    { "scenario": "Both pickup and delivery addresses are empty strings", "expected_behavior": "Should be rejected — an empty string is not a valid address. The spec says 'there is a pickup address,' implying a meaningful value." },
    { "scenario": "Weight is provided as a floating-point with high precision (e.g., 10.0000000001 kg)", "expected_behavior": "Should be classified as Heavy if it exceeds 10 kg after rounding rules are applied. Precision policy should be defined." }
  ],

  "business_impact": {
    "financial": "Weight bracket classification directly drives pricing. Incorrect bracket assignment means revenue leakage (undercharging) or customer disputes (overcharging). Boundary errors at 10 kg and 50 kg thresholds are highest-risk.",
    "operational": "Forward-only state machine prevents operational chaos — no re-dispatching delivered parcels, no phantom pickups. Clear lifecycle enables accurate fleet planning and SLA tracking.",
    "user": "Customers expect shipment status to progress logically. Backward state transitions would destroy trust. Clear pricing tiers (Standard/Heavy/Freight) set transparent cost expectations.",
    "risk": "Primary risks: (1) boundary misclassification causing systematic billing errors at scale, (2) state machine bypass allowing delivered shipments to be reopened, corrupting audit trails and proof-of-delivery, (3) missing validation on direct Pending→Delivered skip.",
    "stakeholders_affected": [
      { "group": "Senders (Customers)", "impact": "Pricing transparency, shipment tracking accuracy, trust in delivery finality" },
      { "group": "Recipients", "impact": "Accurate delivery status — no false re-openings after delivery confirmation" },
      { "group": "Operations / Dispatch", "impact": "Clean state machine enables reliable dispatch workflows and SLA monitoring" },
      { "group": "Finance / Billing", "impact": "Weight bracket accuracy directly determines invoice correctness and revenue integrity" },
      { "group": "Compliance / Audit", "impact": "Forward-only state transitions preserve audit trail integrity and proof-of-delivery records" }
    ]
  },

  "confidence": {
    "level": 72,
    "reasoning": "The spec is clear on core lifecycle rules and weight constraints, but leaves several boundary conditions and secondary behaviors unspecified. The bracket boundaries (inclusive vs exclusive at thresholds) are implied but not explicitly stated — I've inferred the most natural interpretation (upper-bound inclusive per bracket). The Pending→Delivered skip is not addressed. Weight precision and address validation rules are absent.",
    "high_confidence_areas": [
      "Forward-only state machine (Pending → In Transit → Delivered)",
      "Delivered is terminal — no further state changes",
      "Weight must be positive and <= 1000 kg",
      "Both addresses required for shipment creation",
      "Three weight brackets exist: Standard, Heavy, Freight"
    ],
    "low_confidence_areas": [
      "Bracket boundary inclusivity (is 10 kg Standard or Heavy? Spec says '0-10 is standard, 10-50 is heavy' — overlap at 10 and 50)",
      "Whether Pending → Delivered skip is allowed or must go through In Transit",
      "Address validation rules beyond presence (format, length, geocoding)",
      "Weight precision — integer-only or decimal, and rounding rules",
      "Whether weight can be modified after creation and whether bracket recalculates"
    ],
    "assumptions": [
      "Bracket boundaries are upper-inclusive: Standard = (0, 10], Heavy = (10, 50], Freight = (50, 1000]. This resolves the overlap in the spec's '0-10 is standard, 10-50 is heavy' phrasing.",
      "Newly created shipments start in Pending — not explicitly stated but strongly implied by the lifecycle description.",
      "Weight is required at shipment creation time — implied by the pricing model but not explicitly stated.",
      "Addresses must be non-empty meaningful values, not just present as null vs non-null."
    ]
  },

  "escalations": [
    {
      "type": "ambiguity",
      "description": "The spec describes bracket boundaries with overlap: '0-10 kg is standard, 10-50 kg is heavy.' The value 10 kg belongs to both ranges as written. Similarly, 50 kg appears in both 'heavy' and could be read as the start of 'over 50 kg is freight.' The boundary inclusivity must be clarified.",
      "affected_stakeholders": ["Finance / Billing", "Senders (Customers)"],
      "options": [
        "A) Standard = (0, 10], Heavy = (10, 50], Freight = (50, 1000] — upper-inclusive per bracket",
        "B) Standard = [0, 10), Heavy = [10, 50), Freight = [50, 1000] — lower-inclusive per bracket"
      ],
      "recommendation": "Option A (upper-inclusive). '0-10 is standard' most naturally reads as 'up to 10 kg.' The phrase 'over 50 kg is freight' strongly implies 50 kg itself is NOT freight. Recommend confirming with PM."
    },
    {
      "type": "ambiguity",
      "description": "The spec does not address whether a shipment can skip from Pending directly to Delivered, bypassing In Transit. In real logistics this would be unusual but could represent edge cases like same-location pickup/delivery or cancelled-then-completed flows.",
      "affected_stakeholders": ["Operations / Dispatch", "Compliance / Audit"],
      "options": [
        "A) Strictly sequential: Pending → In Transit → Delivered only",
        "B) Allow skip: Pending → Delivered permitted"
      ],
      "recommendation": "Option A (strictly sequential). In real logistics, a parcel must physically transit before delivery. Skipping In Transit would corrupt tracking records and SLA calculations. Recommend confirming with PM."
    },
    {
      "type": "missing_context",
      "description": "Weight is referenced for pricing but it is unclear whether weight is required at shipment creation, whether it can be updated after creation, and if so whether the weight bracket recalculates. Also unclear: is weight integer-only or decimal, and what precision?",
      "affected_stakeholders": ["Finance / Billing", "Operations / Dispatch"],
      "options": [
        "A) Weight is immutable after creation, required at creation, decimal with 2-digit precision",
        "B) Weight can be updated (e.g., after physical measurement at warehouse) and bracket recalculates"
      ],
      "recommendation": "Clarify with PM. Option B is more realistic for logistics (estimated vs actual weight), but requires defining when weight becomes locked (e.g., once In Transit)."
    }
  ],

  "rejection_reasons": []
}

